INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('How can we create a good environment for ourselves? (Lecture - 30)', 'Read good books', 'Watch popular shows', 'Keep negative thoughts', 'Eat more food', 'A', 'B');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Rajesh has cleared his 12th standard exam with good grades. He is confused about the selection of his degree course. What should Rajesh do? (Lecture 16)', 'He should seek some advice in choosing a course that is relevant to his prospective career choice.', 'He should select the course that is most popular with his friends and other students.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Amit is a very bright student. He wants to be an engineer and get entry to the best company in his field. He has just got admission into the engineering institute that he desired, now what should Amit follow: (Lecture 16)', 'Amit should try to settle down into the new atmosphere, observe what others are doing and should follow in their footsteps.', 'Amit should define some short-term goals that will help get entry into the company of his choice', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Anjali is an average Student. She has set a clear long-term goal to join the Civil Services. With the help from experts, she has set some short-term goals too, but she is struggling to achieve them. What should she do? (Lecture 16)', 'Anjali should change her long-term goal to something easier', 'Anjali should create a daily routine that will help her achieve her short-term targets', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('What can we learn from the following Alexander-The-Great quote: "Bury my body, do not build any monument, keep my hands outside so that the world knows the person who won the world had nothing in his hands when dying"? (Lecture 16)', 'Great people often die unhappy.', 'Material gain and reputation are not the most important thing in life.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Neel''s friend encourages him to smoke some cigarettes because he believes that ‘there is no harm in trying it once''. Why should Neel decline his friend''s offer to smoke? (Lecture 17)', 'Smoking is harmful and can become addictive.', 'Smoking can be an unpleasant experience for beginners.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Devashish Ghosh, an intelligent youth, had great career prospects. But he became addicted to various drugs. The Defence Ministry found him in possession of drugs and blacklisted him. This ruined his career. How do you think Devashish Ghosh could have avoided this situation? (Lecture 17)', 'Devashish should have only used drugs occasionally during his vacation time.', 'Devashish should not have taken the risk. He should have avoided the use of drugs completely.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Sejal often gets stressed because she has financial difficulties. She is also addicted to cigarettes, smoking 15 cigarettes daily. She refuses to stop smoking because she says that it helps control her stress. Do you think it is beneficial for her to stop smoking? (Lecture 17)', 'Yes. Spending money on cigarettes is wasting her money. If she can be strong and give up her addiction, then this will be more beneficial in the long term.', 'No. By trying to stop smoking she will get more stressed. Which will only make her situation worse.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('A charitable NGO is planning on building a school for the local orphans. During the discussion, one volunteer suggests installing air coolers into the school so that the students feel comfortable during the summer. Some other members disagree as it would mean increasing the fundraising target by 5%. What would you suggest? (Lecture 18)', '"It will be worth the extra effort of fundraising so that the students feel more comfortable."', '"We should only focus on the basic necessities needed to build the school."', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('The local community has organised a one-day cleanup event. The organisers have invited the local minister alongside sixty members of the community to clean all the trash in the village river. The local media has been asked to attend the event to record and publicise the good efforts of the minister and community. However, the media has not confirmed their invitation and so their attendance cannot be guaranteed. Upon hearing this, the minister is considering whether to attend the event or not, what would you advise him? (Lecture 18)', 'You should request the organisers to postpone the event until the media guarantees their attendance.', 'You should attend the event even if the media does not attend because it is a good cause.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Sanjay is part of a district football team. So far, he has played a crucial role in getting his team to the finals of the state championship. Today, Sanjay has been scheduled to play in the final match, but Sanjay''s back has started hurting in a way that affects his performance. Help him decide what advice he should take from the options below. (Lecture 19)', 'Do not tell anyone and play the match even with the chance that your performance might get impacted. If you do not play the match, you might not get the recognition you deserve.', 'Alert your coach about it, even if that means he may not let you play in the match. It is better to do what is best for the team even if it means missing out on a big opportunity.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Anmol has been given the responsibility to lead a new project for an IT company. One of his responsibilities is to hire new people into his team. Which approach do you think is the best to take? (Lecture 19)', 'Make a team with less diversity to help avoid conflicts and confusion.', 'Make a team with more diversity to increase innovation, different perspectives, and greater acceptance.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Which attribute of a good team player is emphasised in the quote, "Teamwork: simply stated, it is less me and more we."? (Lecture 19)', 'A good team player should be able to sacrifice his personal gains for the success of the team', 'A good team player should be able to change his personality to fit in with the team.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('What is the best way to describe the leadership concept ''Leading Without Leading''? (Lecture 21)', 'Great leaders should delegate as much work as possible to free up their time for the most important things.', 'Great leaders can lead through a good example instead of a more commanding nature.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('What leadership style best describes the following quotation: "As we look ahead into the next century, leaders will be those who empower others." [Bill Gates] (Lecture 21)', 'Delegative Leadership', 'Servant Leadership', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Jeff Garcia, a former American football player, was admired for his leadership in the following way: "Jeff Garcia showed up every day to do the work - first one to practice, first one out the tunnel - and in the way he carried himself he demanded that you do the same." [Jon Dorenbos, Life is Magic], Which of the following leadership style best represents the above quote? (Lecture 21)', 'Lead by example', 'First in, is the first to win', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Manan is an intelligent college student. But he often gets late to class, and he rarely submits the assignments on time. His professor is new at his role and has not noticed Manan''s absences. What should Manan do? (Lecture 23)', 'Manan can maintain his lifestyle but should also stay aware such that his grades do not suffer as a result.', 'He should become more punctual in his attendance and submissions.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('What is the closest interpretation of the following quote: "‘Small things make perfection, but perfection is not a small thing"? (Lecture 23)', 'Try to bring perfection into the small tasks of your day-to-day life. Perfection in small tasks drives our life to perfection.', 'Perfection is very important for your career. Bring perfection into your important tasks as a student or as a professional.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Archana is a software engineer. She likes to work on program designing and coding. But she does not like to do the supporting documentation work. She finds it unimportant as it is not normally used by anyone. It needs to be done to adhere to the general organization standards. What should Archana do? (Lecture 23)', 'Complete the documentation work by noting down only the biggest details. The supporting document feels unimportant and is unlikely to be used anyway.', 'Complete the documentation work sincerely. Follow the organization guidelines to specify the details. Even if it seems unimportant, she should be sincere in completing her work.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Every morning Steve Jobs asked himself: "If today was the last day of my life, would I want to do what I am about to do today?" From the following two statements, pick that which you think best explains Jobs'' quote. (Lecture 24)', 'Jobs wanted to remind himself of what is most important in his life and to continue working in that direction.', 'Jobs wanted to focus more on achieving short term benefits instead of making long term investments.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('"Death teaches about life." Which of the following statements best explains the importance of this quotation? (Lecture 24)', 'We should accept that everything has an ending point.', 'Realizing our life as finite can improve our productivity, clarity, and stability.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Anamika and Aditi are friends. But Aditi forgot to invite Anamika to her birthday celebration. Anamika felt upset that she was left out. A few weeks later, Anamika''s birthday anniversary is now soon approaching, and she is planning her birthday celebration. What should Anamika do? (Lecture 25)', 'Invite Aditi to her birthday celebration. This will make Aditi realise her mistake and more likely to apologise.', 'Invite Aditi to her birthday celebration and bridge the gap in their friendship.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Due to poor exam results, Rahul''s father scolded him in front of his friends. Rahul felt it was insulting and had an argument with her father in the evening because of this reason. After the argument, Rahul felt even more disturbed. What advice would you give to Rahul? (Lecture 25)', 'Meet your father and say sorry to him. A gentle talk may inspire your father to realise that he should not have scolded you in front of your friends.', 'Meet your father and say sorry to him. Accept your fault and apologise for your improper behaviour. Promise him that you will work harder for your studies from now onward.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Avinash stays in a hostel. Raj is his roommate. Raj is very notorious and has a habit of mocking everyone most of the time. After a few months, Raj stopped teasing Avinash. But Avinash has started to hate Raj because of his nature. He gets disturbed just by looking at Raj. What should Avinash do to feel more positive? (Lecture 25)', 'Change rooms and avoid speaking to Raj. That way he cannot ruin his mood.', 'Try and forgive Raj for his mocking nature. Focus on his positive qualities instead.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('‘Resentment is like drinking poison and then hoping it will kill your enemies.'' - What is the most useful lesson to learn from this famous quote by Nelson Mandela? (Lecture 25)', 'Keeping bitter emotions for those who have hurt us will only prove to be self-destructive. So, we should learn to forgive others for our own peace of mind.', 'Keeping bitter emotions for your enemies is unlikely to inflict harm on them. It is better to act upon it instead.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Which of the following do you think is the most effective method to become more productive? (Lecture 26)', 'Create and follow a schedule while neglecting everything else.', 'Find your biggest priorities and ensure they are scheduled and completed.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Jatin has important exams approaching in three weeks and is trying to prepare himself accordingly. He is aware that he will need to commit a decent amount of time to study, but he would also like to give some time for exercise. How would you suggest that he balances his time? (Lecture 26)', 'Jatin should schedule at least 30 minutes of exercising every morning before studying.', 'Jatin should commit to exercising only on the days when he finds spare time after completing his studies and other responsibilities.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Anil is currently learning to code while also working part-time as an IT consultant. Every morning after studying at home, he will drive to meet his client at 11 AM. The journey normally takes around 44 minutes. Anil is trying to decide how to fit this journey into his schedule. Which of the following options do you think is more appropriate? (Lecture 26)', 'Anil should leave home at 10:15 AM, so as not to potentially waste any time waiting around.', 'Anil should leave home at 10:05 AM, so to include buffer time into his schedule.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('Anjali sleeps for 7 hours a night and wakes up a few hours later on Sunday. However, on Monday mornings, Anjali often feels more tired than usual and finds it harder to concentrate. How do you think Anjali should adjust her sleep pattern so that she does not feel extra tired on Monday mornings? (Lecture 27)', 'Anjali should try to sleep extra early on Sunday night so that she feels well-rested on Monday morning.', 'Anjali should try to keep the same sleep schedule on weekdays and weekends so as not to disturb her body clock.', '', '', 'B', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('The monsoon season saw some serious flooding. The structure of your house has been significantly damaged because of excessive water exposure. The repair work will cost you ₹5 lakh. How should you go about financing the repair? (Lecture 29)', 'Check if your insurance covers water damage, make the necessary insurance claim and withdraw the balance from your emergency fund.', 'Check if your insurance covers water damage, make the necessary insurance claim and borrow the balance of the money from a bank.', '', '', 'A', 'C');
INSERT INTO questions (question, option_a, option_b, option_c, option_d, correct_option, section) VALUES ('After graduating, Shivani started working as a data scientist for the last 4 years. She has been earning ₹7 lakh rupees every year. Now that her 25th birthday is approaching, she is wondering about the best time to start a retirement fund. What financial plan will allow her to benefit the most? (Lecture 29)', 'Start investing into a retirement fund straight away to earn more money through compound interest.', 'For the next 5-7 years, she should keep her money free so she can spend it. She can then start a retirement fund afterwards.', '', '', 'A', 'C');
